  ('PRD0551','Анализ косметики',2351,'Крем для лица с церамидами Q+A Ceramide (50 г)','Крем для лица с церамидами Q+A Ceramide (50 г)','Q+A','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','Для восстановления не хватает необходимого количества и разнообразия восстанавливающих компонентов. Этот крем подойдет для базового ухода за не сухой или не сохнущей кожей','Содержание восстанавливающих компонентов ограничено. Подходит для базового ухода за нормальной кожей без выраженной сухости.',false,NULL,NULL,NULL,1800,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',21,'B0274'),
  ('PRD0552','Анализ косметики',2373,'The ACT крем для лица с витамином C дневной','The ACT крем для лица с витамином C дневной','The Act','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','отличный восстанавливающий крем, который подойдет для коррекции сухости и в комплексном уходе будет полезным в решении вопроса обезвоженности. Хоть и ламеллярные эмульгаторы в составе есть ❌производитель не позиционирует продукт как ламеллярный ❌микроскопирование не проводилось Значит эмульсия прямая, а не ламеллярная. Ведь мы помним, что для создания ламеллярной эмульсии требуется специальное оборудование и микроскопия.','Восстанавливающий крем для коррекции сухости и обезвоженности в комплексном уходе. Несмотря на наличие ламеллярных эмульгаторов, производитель не позиционирует продукт как ламеллярный и микроскопия не проводилась, поэтому эмульсию следует считать прямой.',true,NULL,NULL,NULL,900,0,0,2,NULL,NULL,0,0,0,0,true,false,NULL,'Бюджетная',37,'B0333'),
  ('PRD0553','Анализ косметики',2411,'The ACT крем для лица ночной','The ACT крем для лица ночной','The Act','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо',NULL,NULL,false,NULL,NULL,NULL,900,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',32,'B0333'),
