  ('PRD0555','Анализ косметики',2470,'Prequel GLEANSER NON-DRYING GLYCERIN CLEANSER','Prequel GLEANSER NON-DRYING GLYCERIN CLEANSER','Prequel','Очищающее средство','Уход за кожей / Очищение / Очищающее средство','Лицо','супер состав','Продуманный, качественный состав.',true,NULL,NULL,NULL,1800,0,0,0,NULL,NULL,0,0,0,0,false,true,NULL,'Средняя',20,'B0270'),
  ('PRD0556','Анализ косметики',2491,'La Roshe Posay Toleriane Micellar Water','La Roshe Posay Toleriane Micellar Water','La Roche-Posay','Мицеллярная вода','Уход за кожей / Очищение / Мицеллярная вода','Лицо','мицеллярный гель, в его составе полоксамер 184, типичный ПАВ для мицеллярных средств. Подойдет всем, и даже чувствительной коже и коже с розацеа. Конечно, полоксамер не лучшее средство для очищения обезвоженной кожи, но все же при правильном и быстром использовании очищения, при правильном уходе, никаких проблем возникнуть не должно.','Мицеллярный гель на основе полоксамера 184 — типичного ПАВ для мицеллярных средств. Подходит всем типам кожи, включая чувствительную и склонную к розацеа. Для обезвоженной кожи рекомендуется кратковременное очищение в сочетании с последующим уходом.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,11,'B0197'),
  ('PRD0557','Анализ косметики',2503,'Bioderma Sensibio H2O Micellar Water','Bioderma Sensibio H2O Micellar Water','Bioderma Sensibio','Мицеллярная вода','Уход за кожей / Очищение / Мицеллярная вода','Лицо',NULL,NULL,false,NULL,NULL,NULL,2000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',10,'B0059'),
  ('PRD0558','Анализ косметики',2514,'By Wishtrend Green Tea & Enzyme Milky Foaming Wash','By Wishtrend Green Tea & Enzyme Milky Foaming Wash','By Wishtrend','Пенка','Уход за кожей / Очищение / Пенка','Лицо','Пример очищения в виде жидкого формата кускового мыла. Сухость и обезвоженность неизбежно настигнут в ближайшее время использования.','Очищающее средство на мыльной основе. При регулярном использовании возможно появление сухости и обезвоженности кожи.',false,NULL,NULL,NULL,1800,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',35,'B0064'),
  ('PRD0559','Анализ косметики',2551,'OBAGI-C® FX C-CLEANSING GEL Vitamin C Cleansing Gel','OBAGI-C® FX C-CLEANSING GEL Vitamin C Cleansing Gel','OBAGI-C','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','Будет сушить кожу с нарушенным барьером и сухостью, потому что использованы жесткие анионные ПАВ','Содержит жёсткие анионные ПАВ; может подсушивать кожу с нарушенным барьером и склонностью к сухости.',false,NULL,NULL,NULL,5000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',18,'B0241'),
  ('PRD0560','Анализ косметики',2570,'Likato Professional Vitamin C, Panthenol and Citric Acid Cleansing Foam','Likato Professional Vitamin C, Panthenol and Citric Acid Cleansing Foam','Likato Professional','Пенка','Уход за кожей / Очищение / Пенка','Лицо','Может вызвать контактный дерматит, так как содержит раздражающий ингредиент','Содержит потенциально раздражающий компонент; возможны реакции у чувствительной кожи.',false,NULL,NULL,NULL,580,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',14,'B0206'),
  ('PRD0561','Анализ косметики',2586,'Uriage Hyseac Cleansing Gel','Uriage Hyseac Cleansing Gel','Uriage','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо',NULL,NULL,false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,22,'B0350'),
  ('PRD0562','Анализ косметики',2610,'Bioderma Sensibio Gel Moussant','Bioderma Sensibio Gel Moussant','Bioderma Sensibio','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','Комбинация компонентов делают средство мягким и хорошо очищающим. SODIUM LAUROYL SARCOSINATE еще и пену хорошую придаст','Сочетание компонентов обеспечивает мягкое и эффективное очищение. Sodium Lauroyl Sarcosinate способствует образованию плотной пены.',true,'Жирная','Жирная',NULL,1000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',18,'B0059'),
  ('PRD0563','Анализ косметики',2629,'LABORATORIOS BABE Гель для умывания мицеллярный успокаивающий, 245 мл','LABORATORIOS BABE Гель для умывания мицеллярный успокаивающий, 245 мл','LABORATORIOS BABE','Мицеллярная вода','Уход за кожей / Очищение / Мицеллярная вода','Лицо','Отличное, мягкое средство, подходит даже чувствительным и аллергикам','Мягкое средство, подходит чувствительной и склонной к аллергии коже.',false,NULL,NULL,NULL,1200,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',17,'B0190'),
  ('PRD0564','Анализ косметики',2647,'LSANIC Гель для умывания мягкий отшелушивающий с AHA-кислотами, 150 мл','LSANIC Гель для умывания мягкий отшелушивающий с AHA-кислотами, 150 мл','LSANIC','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','Пример очищения в виде жидкого формата кускового мыла. Сухость и обезвоженность неизбежно настигнут в ближайшее время использования.','Очищающее средство на мыльной основе. При регулярном использовании возможно появление сухости и обезвоженности кожи.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,29,'B0195'),
  ('PRD0565','Анализ косметики',2678,'Успокаивающий гель для умывания с азуленом и церамидами SUR.MEDIC+ Azulene Soothing pH Cleanser','Успокаивающий гель для умывания с азуленом и церамидами SUR.MEDIC+ Azulene Soothing pH Cleanser','SUR.MEDIC','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','Очищение мягкое, Potassium без Hidroxide. Очищение на основе глицерина, подойдет сухой, обезвоженной, раздраженной и чувствительной коже.','Мягкое очищение на основе глицерина, без гидроксида калия. Подходит сухой, обезвоженной, раздражённой и чувствительной коже.',true,NULL,NULL,NULL,800,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',63,'B0302'),
  ('PRD0566','Анализ косметики',2742,'NSC Name Skin Care Vitamin C & Curcuma Cleanser Gel','NSC Name Skin Care Vitamin C & Curcuma Cleanser Gel','NSC Name Skin Care','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','Пример очищения со смесью мягких и жестких ПАВ. Смеси мягче воздействуют на кожу, нежели очищение только на основе жестких ПАВ. Может качественно очистить жирную, очистить кожу после плотного и сценического макияжа. Жесткие ПАВ разбивают молекулу жира на мелкие частички, что хорошо смывается потоком воды, и у жирной кожи липидов достаточно, чтобы не навредить коже. Но и сочетание жестких ПАВ с кислотами и ретиноидами может истончать и обезвоживать кожу, так что “ прислушивайтесь ” к коже.','Очищение на основе смеси мягких и жёстких ПАВ, которая воздействует деликатнее, чем составы только на жёстких ПАВ. Эффективно для жирной кожи и удаления плотного макияжа. Сочетание жёстких ПАВ с кислотами и ретиноидами может истончать и обезвоживать кожу, поэтому рекомендуется ориентироваться на состояние кожи.',false,'Жирная','Жирная',NULL,500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',17,'B0233'),
  ('PRD0567','Анализ косметики',2760,'La roshe posay Effaclar Purifying Foaming Gel','La roshe posay Effaclar Purifying Foaming Gel','La Roche-Posay','Пенка','Уход за кожей / Очищение / Пенка','Лицо','жесткий состав, на сегодняшний день нет необходимости использовать жесткие ПАВ, ведь они агрессивно очищают кожу.','Состав на основе жёстких ПАВ, которые обеспечивают агрессивное очищение.',false,NULL,NULL,NULL,1400,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',20,'B0197'),
  ('PRD0568','Анализ косметики',2781,'NEXTBEAU Очищающая пенка для умывания с центеллой азиатской для восстановления кожи, 100 мл','NEXTBEAU Очищающая пенка для умывания с центеллой азиатской для восстановления кожи, 100 мл','NEXTBEAU','Пенка','Уход за кожей / Очищение / Пенка','Лицо','Слишком жесткий состав. На основе жестких ПАВ на основе мыла и один мягкий ПАВ никак не может исправить ситуацию. Тут происходит гидролиз жирных кислот щелочью potassium hydroxide, получается жесткое для лица жидкое мыло','Жёсткий состав на мыльной основе: гидролиз жирных кислот гидроксидом калия даёт жидкое мыло, агрессивное для кожи лица. Один мягкий ПАВ существенно не смягчает воздействие.',false,NULL,NULL,NULL,405,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',25,'B0230'),
  ('PRD0569','Анализ косметики',2808,'VICHY Освежающий очищающий гель Fresh Cleansing Gel Purete Thermale, 200 мл','VICHY Освежающий очищающий гель Fresh Cleansing Gel Purete Thermale, 200 мл','Vichy','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','гель норм','Гель приемлемого качества.',true,NULL,NULL,NULL,1500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',14,'B0358'),
  ('PRD0570','Анализ косметики',2823,'VICHY Очищающая пенка, придающая сияние Ea Moussante Nett Purete Thermale, 150 мл','VICHY Очищающая пенка, придающая сияние Ea Moussante Nett Purete Thermale, 150 мл','Vichy','Пенка','Уход за кожей / Очищение / Пенка','Лицо','пенка должна быть мягкой для сухой кожи, а тут жесткий пав','Содержит жёсткий ПАВ, что нежелательно для пенки, предназначенной сухой коже.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,19,'B0358'),
  ('PRD0571','Анализ косметики',2843,'Planeta organica pure пенка для лица очищающая 150 мл','Planeta organica pure пенка для лица очищающая 150 мл','Planeta Organica','Пенка','Уход за кожей / Очищение / Пенка','Лицо','А вот и мягкий состав очищения. Спирт в составе выполняет роль консерванта, что характерно для органик косметики','Мягкий очищающий состав. Спирт выполняет роль консерванта, что характерно для органической косметики.',true,NULL,NULL,NULL,300,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',12,'B0269'),
  ('PRD0572','Анализ косметики',2856,'COSMEDIX Пенка очищающая для лица CLARIFY 150ml Clarify Salicylic Acid Foaming Cleanser','COSMEDIX Пенка очищающая для лица CLARIFY 150ml Clarify Salicylic Acid Foaming Cleanser','COSMEDIX','Пенка','Уход за кожей / Очищение / Пенка','Лицо','жесткие ПАВ + кислоты обезжиривают кожу и являются хорошим предпилинговым средством, не часто','Сочетание жёстких ПАВ и кислот обезжиривает кожу; подходит как предпилинговое средство для нечастого применения.',false,NULL,NULL,NULL,5000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',39,'B0074'),
  ('PRD0573','Анализ косметики',2896,'PAYOT Пенка для лица очищающая Nue, 150 мл','PAYOT Пенка для лица очищающая Nue, 150 мл','PAYOT','Пенка','Уход за кожей / Очищение / Пенка','Лицо','супер состав, в составе 4 мягких ПАВ. Средство бережно очистит любую кожу, даже чувствительную и сухую','Качественный состав с четырьмя мягкими ПАВ. Бережно очищает любую кожу, включая чувствительную и сухую.',true,NULL,NULL,NULL,1700,0,0,0,NULL,NULL,0,0,0,0,false,true,NULL,'Средняя',23,'B0253'),
  ('PRD0574','Анализ косметики',2920,'Nivea Caring Мицеллярная вода','Nivea Caring Мицеллярная вода','Nivea','Мицеллярная вода','Уход за кожей / Очищение / Мицеллярная вода','Лицо','супер состав, в составе 4 мягких ПАВ. Вполне мягкая мицеллярная вода.','Качественный состав с четырьмя мягкими ПАВ. Мягкая мицеллярная вода.',true,NULL,NULL,NULL,450,0,0,0,NULL,NULL,0,0,0,0,false,true,NULL,'Бюджетная',18,'B0240'),
  ('PRD0575','Анализ косметики',2940,'La roche-posay мицеллярная вода ultra reactive очищение для чувствительной и склонной к аллергии кожи лица и глаз 400 мл','La roche-posay мицеллярная вода ultra reactive очищение для чувствительной и склонной к аллергии кожи лица и глаз 400 мл','La Roche-Posay','Мицеллярная вода','Уход за кожей / Очищение / Мицеллярная вода','Лицо','почти все хорошо, мягкий состав, но этот консервант, Mytrimonium Bromide - катионный ПАВ, встраиваются в липидный барьер и притягиваются к клеткам кожи, потому и может потенциально повреждать защитный барьер и сушить кожу. Все-таки лучше подобные составы не использовать в составе как смываемых, так и несмываемых продуктов.','В целом мягкий состав. Содержит катионный ПАВ Behentrimonium Bromide, который встраивается в липидный барьер и может потенциально нарушать защитный барьер и подсушивать кожу. Подобные компоненты нежелательны как в смываемых, так и в несмываемых продуктах.',false,NULL,NULL,NULL,2000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',10,'B0197'),
  ('PRD0576','Анализ косметики',2951,'Avene Hydrance Rich увлажняющий насыщенный крем 40 мл','Avene Hydrance Rich увлажняющий насыщенный крем 40 мл','Avene','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','масла - есть окклюзия (пленка) - есть физиологичнык липиды - нет Потому подойдет в качестве плотного крема, который запечатает тонер и сыворотку на коже. Накопительного восстанавливающего эффекта не будет.','В составе есть масла и окклюзивная плёнка, но отсутствуют физиологичные липиды. Подходит как плотный крем для закрепления тонера и сыворотки; накопительного восстанавливающего эффекта не оказывает.',false,NULL,NULL,NULL,2200,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',24,'B0039'),
  ('PRD0577','Анализ косметики',2976,'CLINIQUE Интенсивно увлажняющий гель-крем на 100 часов Moisture Surge, 15 мл','CLINIQUE Интенсивно увлажняющий гель-крем на 100 часов Moisture Surge, 15 мл','CLINIQUE','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','увлажняющий крем','Увлажняющий крем.',true,NULL,NULL,NULL,4000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',43,'B0069'),
  ('PRD0578','Анализ косметики',3020,'Clinique Moisture Surge Intense 72H Lipid-Replenishing Hydrator','Clinique Moisture Surge Intense 72H Lipid-Replenishing Hydrator','Clinique','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','Подойдет просто как ежедневный уход за нормальной, комби и жирной кожей. Крем позиционирует себя как липидовосстанавливающий и эта функция в нем и правда есть, только слабо выражена, ведь липидовосстанавливающих компонентов в составе очень мало.','Подходит для ежедневного ухода за нормальной, комбинированной и жирной кожей. Заявленная липидовосстанавливающая функция выражена слабо из-за невысокого содержания соответствующих компонентов.',true,NULL,NULL,NULL,2000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',39,'B0069'),
  ('PRD0579','Анализ косметики',3060,'CELIMAX Крем для лица Dual Barrier Skin Wearable Cream, 50 мл','CELIMAX Крем для лица Dual Barrier Skin Wearable Cream, 50 мл','Celimax','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','Отличный крем для сухой кожи с липидовосстанавливающими компонентами. Чем суше кожа, тем больше липидовосстанавливающих единиц косметики будет в уходе.','Крем для сухой кожи с липидовосстанавливающими компонентами. Чем суше кожа, тем больше таких средств рекомендуется включать в уход.',true,NULL,NULL,NULL,2300,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',39,'B0081'),
  ('PRD0580','Анализ косметики',3101,'La Roche Posay Toleriane Sensitive Увлажняющий крем для лица с чувствительной кожей, успокаивающий уход с пребиотической формулой, 40 мл','La Roche Posay Toleriane Sensitive Увлажняющий крем для лица с чувствительной кожей, успокаивающий уход с пребиотической формулой, 40 мл','La Roche-Posay','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','Сухую и обезвоженную кожу в самостоятельном варианте не восстановит, ведь в составе нет липидовосстанавливающих компонентов.','Не содержит липидовосстанавливающих компонентов, поэтому самостоятельно не восстанавливает сухую и обезвоженную кожу.',false,NULL,NULL,NULL,1200,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',19,'B0197'),
